import type {
  SDUIComponentRegistry,
  SDUIComponentRenderer,
} from '../models';

export function createRegistry(
  initial?: SDUIComponentRegistry,
): SDUIComponentRegistry {
  return { ...initial };
}

export function registerComponent(
  registry: SDUIComponentRegistry,
  type: string,
  renderer: SDUIComponentRenderer,
): SDUIComponentRegistry {
  return { ...registry, [type]: renderer };
}

export function getRenderer(
  registry: SDUIComponentRegistry,
  type: string,
): SDUIComponentRenderer | undefined {
  return registry[type];
}

const defaultRegistry: SDUIComponentRegistry = {};

export function getDefaultRegistry(): SDUIComponentRegistry {
  return defaultRegistry;
}

export function registerToDefault(
  type: string,
  renderer: SDUIComponentRenderer,
): void {
  defaultRegistry[type] = renderer;
}

