import React from 'react';
import { ListTextIcon } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface ListTextIconItem {
  icon: string;
  iconColor?: string;
  iconColorShape?: string;
  description: string;
  hasBackgroundIcon?: boolean;
}

interface ListTextIconProps extends SDUIComponentProps {
  items: ListTextIconItem[];
  type?: string;
  ml?: string;
  mr?: string;
  mb?: string;
}

export default function ListTextIconAdapter({
  props,
}: {
  props: ListTextIconProps;
  context: SDUIContext;
}) {
  const { items, type = 'list', ml, mr, mb } = props;

  return (
    <ListTextIcon
      items={items as any}
      type={type}
      ml={ml}
      mr={mr}
      mb={mb}
    />
  );
}
